Here's the complete implementation of the functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Insert each record
  for (const auto& record : records) {
    sqlgen::insert(conn, record).value();
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const auto& new_value) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Map table names to their primary key columns
  static const std::map<std::string, std::string> primary_keys = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  // Get the primary key column for the table
  auto it = primary_keys.find(table_name);
  if (it == primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& pk_column = it->second;

  // Build and execute the update query
  std::string query = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_column + " = ?";

  sqlgen::sqlite::connect(db_path)
    .and_then([&](auto&& conn) {
      return sqlgen::exec(conn, query, new_value, record_id);
    })
    .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Map table names to their primary key columns
  static const std::map<std::string, std::string> primary_keys = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  // Get the primary key column for the table
  auto it = primary_keys.find(table_name);
  if (it == primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& pk_column = it->second;

  // Build and execute the delete query
  std::string query = "DELETE FROM " + table_name + " WHERE " + pk_column + " = ?";

  sqlgen::sqlite::connect(db_path)
    .and_then([&](auto&& conn) {
      return sqlgen::exec(conn, query, record_id);
    })
    .value();
}
```

Key implementation details:

1. **`add_eas_records`**:
   - Uses the templated `sqlgen::insert` function to insert each record
   - Leverages the type safety of the SQLGen library
   - Works with any of the defined struct types (Student, Course, Score, Major)

2. **`modify_eas_records_by_id`**:
   - Uses a map to determine the primary key column for each table
   - Builds a parameterized SQL UPDATE query
   - Uses `sqlgen::exec` with parameters to safely execute the query

3. **`delete_eas_records_by_id`**:
   - Similar to the modify function but builds a DELETE query
   - Uses the same primary key mapping approach
   - Safely executes the delete operation with parameters

The implementation handles:
- Proper database connection management
- Parameterized queries to prevent SQL injection
- Error handling through the `value()` method
- Type safety through the SQLGen library's features
- Support for all four table types defined in the common header

