#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  SQLGEN_VIEW(CourseStatsView);
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  // Connect to the SQLite database
  sqlgen::sqlite::connection db("test_db.sqlite");

  // Create tables if they don't exist
  db.create_table<Course>();
  db.create_table<Enrollment>();

  // Build the query using sqlgen
  auto query = sqlgen::query<Course>()
      .left_join<Enrollment>(sqlgen::on<Course, Enrollment>(&Course::course_id, &Enrollment::course_id))
      .group_by(&Course::course_id, &Course::title)
      .select(
          &Course::title,
          sqlgen::count(&Enrollment::enrollment_id).as("student_count"),
          sqlgen::avg(&Enrollment::grade).as("avg_grade")
      );

  // Execute the query and get results
  auto results = db.query<CourseStatsView>(query);

  // Convert CourseStatsView to CourseStats
  std::vector<CourseStats> course_stats;
  for (const auto& view : results) {
    course_stats.push_back(CourseStats{
      view.title,
      view.student_count,
      view.avg_grade
    });
  }

  return course_stats;
}

}  // namespace query_course_enrollment_stats
