namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // Connect to the SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Start with base SELECT query
    auto query = sqlgen::select<Book>();

    // Add WHERE clauses dynamically based on provided filters
    if (filters.title_keyword.has_value()) {
        query = query.where(sqlgen::like(&Book::title, "%" + filters.title_keyword.value() + "%"));
    }

    if (filters.min_year.has_value()) {
        query = query.where(sqlgen::ge(&Book::year, filters.min_year.value()));
    }

    if (filters.genre.has_value()) {
        query = query.where(sqlgen::eq(&Book::genre, filters.genre.value()));
    }

    if (filters.max_price.has_value()) {
        query = query.where(sqlgen::le(&Book::price, filters.max_price.value()));
    }

    // Execute the query and return results
    return query.exec(db);
}

}  // namespace query_search_books_by_criteria
```

Key features of this implementation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the SQLite database.

2. **Base Query**: Starts with `sqlgen::select<Book>()` to create the base SELECT query.

3. **Dynamic WHERE Clauses**: 
   - Uses `sqlgen::like()` with wildcards for title keyword search
   - Uses `sqlgen::ge()` (greater than or equal) for minimum year
   - Uses `sqlgen::eq()` (equal) for genre matching
   - Uses `sqlgen::le()` (less than or equal) for maximum price

4. **Conditional Filtering**: Each filter is only added if it has a value (not null/empty).

5. **Query Execution**: The final query is executed with `.exec(db)` and returns the vector of Book objects.

The `sqlgen` library's fluent interface makes it easy to build dynamic queries by chaining `.where()` clauses conditionally based on the provided filters.

