```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <stdexcept>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  if (amount <= 0) {
    throw std::invalid_argument("Transfer amount must be positive");
  }

  if (from_account_id == to_account_id) {
    throw std::invalid_argument("Cannot transfer to the same account");
  }

  // Connect to the database
  sqlgen::SQLiteDB db("test_db.sqlite");

  try {
    // Begin transaction
    db.execute("BEGIN TRANSACTION");

    // Check if sender has sufficient funds
    auto sender = db.select_one<Account>(sqlgen::where(&Account::account_id) == from_account_id);
    if (!sender) {
      throw std::runtime_error("Sender account not found");
    }

    if (sender->balance < amount) {
      throw std::runtime_error("Insufficient funds");
    }

    // Deduct from sender
    auto deduct_result = db.execute(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ?",
      amount, from_account_id
    );

    if (deduct_result.rows_affected() == 0) {
      throw std::runtime_error("Failed to deduct from sender account");
    }

    // Add to receiver
    auto add_result = db.execute(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?", 
      amount, to_account_id
    );

    if (add_result.rows_affected() == 0) {
      throw std::runtime_error("Failed to add to receiver account");
    }

    // Commit transaction
    db.execute("COMMIT");
    return true;

  } catch (const std::exception& e) {
    // Rollback on any error
    db.execute("ROLLBACK");
    throw; // Re-throw the exception to let caller handle it
  }
}

}  // namespace transaction_transfer_funds
```

