std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto db = sqlite::connect("test_db.sqlite");

  // Perform RIGHT JOIN between departments and projects
  // Since SQLite doesn't natively support RIGHT JOIN, we simulate it by swapping tables and using LEFT JOIN
  auto results = db.read<DepProj>(
    select(
      column<Department>(&Department::name).as("department_name"),
      column<Project>(&Project::name).as("project_name")
    )
    .from<Project>()
    .left_join<Department>().on(column<Project>(&Project::department_id) == column<Department>(&Department::department_id))
    // This simulates RIGHT JOIN by including all departments (right table)
  );

  return results;
}

}  // namespace right_join_departments_projects
```

**Important Note:** Since SQLite doesn't natively support RIGHT JOIN, this implementation uses a LEFT JOIN with the tables swapped to simulate the RIGHT JOIN behavior. This approach ensures that all departments are included in the results, even those without associated projects.

