```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <iostream>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Create database connection
    sqlgen::sqlite::connection db("test_db.sqlite");

    // Create table if it doesn't exist
    db.create_table<Inventory>();

    // Perform upsert operation using replace (SQLite's UPSERT)
    db.replace(items);

    // Verify upsert behavior by reading back all items
    auto result = db.select_all<Inventory>();

    // Check if all items were successfully upserted
    for (const auto& item : items) {
      bool found = false;
      for (const auto& db_item : result) {
        if (db_item.item_id == item.item_id) {
          found = true;
          // Verify the data matches
          if (db_item.name != item.name || db_item.quantity != item.quantity) {
            std::cerr << "Data mismatch for item_id: " << item.item_id << std::endl;
            return false;
          }
          break;
        }
      }

      if (!found) {
        std::cerr << "Item not found after upsert: " << item.item_id << std::endl;
        return false;
      }
    }

    std::cout << "Successfully upserted " << items.size() << " inventory items" << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in upsert_inventory_items: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace upsert_inventory_items
