Here is the complete implementation of the `analyze_social_network` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

struct UserFriendCount {
  std::string username;
  int friend_count;
};

struct FriendRecommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    std::vector<FriendConnection> results;

    try {
        // Create in-memory SQLite database
        sqlgen::SQLite db(":memory:");

        // Create User table
        db.execute(R"(
            CREATE TABLE User (
                user_id INTEGER PRIMARY KEY,
                username VARCHAR(50) NOT NULL UNIQUE,
                email VARCHAR(100) NOT NULL UNIQUE,
                join_date DATETIME NOT NULL,
                city VARCHAR(50)
        )");

        // Create Friendship table
        db.execute(R"(
            CREATE TABLE Friendship (
                user_id1 INTEGER,
                user_id2 INTEGER,
                friendship_date DATETIME NOT NULL,
                PRIMARY KEY (user_id1, user_id2),
                FOREIGN KEY (user_id1) REFERENCES User(user_id),
                FOREIGN KEY (user_id2) REFERENCES User(user_id)
            )
        )");

        // Insert users
        for (const auto& user : users) {
            db.execute("INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, ?)",
                      user.user_id.value(), user.username, user.email, user.join_date.value(), user.city.value_or(""));
        }

        // Insert friendships
        for (const auto& friendship : friendships) {
            db.execute("INSERT INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)",
                      friendship.user1_id, friendship.user2_id, friendship.created_at.value());
        }

        // 1. Use SELF-JOIN to find mutual friends (friends who share the same friend)
        auto mutual_friends = db.query<MutualFriendsResult>(R"(
            SELECT u1.username as user1_name, u2.username as user2_name, COUNT(DISTINCT f1.user_id2) as mutual_friends_count
            FROM User u1
            INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
            INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
            INNER JOIN User u2 ON f2.user_id2 = u2.user_id
            WHERE u1.user_id < u2.user_id
              AND EXISTS (
                SELECT 1 FROM Friendship f3 
                WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
              )
            GROUP BY u1.user_id, u2.user_id
            HAVING mutual_friends_count > 0
        )");

        std::cout << "=== Mutual Friends Analysis ===" << std::endl;
        for (const auto& result : mutual_friends) {
            std::cout << result.user1_name << " and " << result.user2_name 
                      << " have " << result.mutual_friends_count << " mutual friends" << std::endl;
        }

        // 2. Use nested query to find users with more than average number of friends
        auto popular_users = db.query<UserFriendCount>(R"(
            SELECT u.username, COUNT(f.user_id2) as friend_count
            FROM User u
            LEFT JOIN Friendship f ON u.user_id = f.user_id1
            GROUP BY u.user_id, u.username
            HAVING friend_count > (
              SELECT AVG(friend_count) 
              FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1) as subq
            )
            ORDER BY friend_count DESC
        )");

        std::cout << "\n=== Users with Above-Average Friends ===" << std::endl;
        for (const auto& result : popular_users) {
            std::cout << result.username << " has " << result.friend_count << " friends" << std::endl;
        }

        // 3. Find friend-of-friend relationships (people connected through exactly one mutual friend)
        auto friend_of_friend = db.query<FriendConnection>(R"(
            SELECT DISTINCT u1.username as user1_name, u3.username as user2_name
            FROM User u1
            JOIN Friendship f1 ON u1.user_id = f1.user_id1
            JOIN User u2 ON f1.user_id2 = u2.user_id
            JOIN Friendship f2 ON u2.user_id = f2.user_id1
            JOIN User u3 ON f2.user_id2 = u3.user_id
            WHERE u1.user_id != u3.user_id
              AND NOT EXISTS (
                SELECT 1 FROM Friendship f3 
                WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
              )
        )");

        std::cout << "\n=== Friend-of-Friend Relationships ===" << std::endl;
        for (const auto& result : friend_of_friend) {
            std::cout << result.user1_name << " is a friend-of-friend with " << result.user2_name << std::endl;
            results.push_back(result); // Add to return results
        }

        // 4. Count friends per user and identify most connected users
        auto friend_counts = db.query<UserFriendCount>(R"(
            SELECT u.username, COUNT(f.user_id2) as friend_count
            FROM User u
            LEFT JOIN Friendship f ON u.user_id = f.user_id1
            GROUP BY u.user_id, u.username
            ORDER BY friend_count DESC
        )");

        std::cout << "\n=== Friend Counts per User ===" << std::endl;
        for (const auto& result : friend_counts) {
            std::cout << result.username << ": " << result.friend_count << " friends" << std::endl;
        }

        // 5. Find users in the same city who are not yet friends (recommendation)
        auto recommendations = db.query<FriendRecommendation>(R"(
            SELECT u1.username as user1_name, u2.username as user2_name, u1.city
            FROM User u1
            JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
            WHERE u1.city IS NOT NULL AND u1.city != ''
              AND NOT EXISTS (
                SELECT 1 FROM Friendship f 
                WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
                   OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
              )
        )");

        std::cout << "\n=== Friend Recommendations (Same City) ===" << std::endl;
        for (const auto& result : recommendations) {
            std::cout << result.user1_name << " and " << result.user2_name 
                      << " both live in " << result.city << " but are not friends" << std::endl;
        }

    } catch (const std::exception& e) {
        std::cerr << "Database error: " << e.what() << std::endl;
    }

    return results;
}

}  // namespace analyze_social_network
```

This implementation:

1. **Creates the required tables** with proper constraints as specified
2. **Uses SELF-JOIN** to find mutual friends between users
3. **Uses nested queries** to find users with above-average friend counts
4. **Finds friend-of-friend relationships** through multiple joins
5. **Counts friends per user** using aggregation functions
6. **Finds friend recommendations** based on same city but not yet friends
7. **Returns friend-of-friend relationships** as the main result vector

The function performs all the required analyses and outputs the results to the console while returning the friend-of-friend relationships as specified by the return type.

