```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <iostream>
#include <vector>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool indicating whether cascade deletion worked correctly.
 */
bool cascade_delete_demo() {
  try {
    // Connect to SQLite database
    sqlgen::SQLite db("test_db.sqlite");

    // Enable foreign key constraints (important for cascade delete to work)
    db.execute("PRAGMA foreign_keys = ON;");

    // Drop tables if they exist (for clean start)
    db.execute("DROP TABLE IF EXISTS Child;");
    db.execute("DROP TABLE IF EXISTS Parent;");

    // Create Parent table
    db.createTable<Parent>();

    // Create Child table with foreign key constraint and CASCADE DELETE
    db.execute(R"(
        CREATE TABLE Child (
            child_id INTEGER PRIMARY KEY,
            parent_id INTEGER,
            note VARCHAR,
            FOREIGN KEY (parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE
        );
    )");

    // Insert parent records
    Parent parent1{1, "Parent One"};
    Parent parent2{2, "Parent Two"};
    db.insert(parent1);
    db.insert(parent2);

    // Insert child records with the same parent_id
    Child child1{1, 1, "Child of Parent One - First"};
    Child child2{2, 1, "Child of Parent One - Second"};
    Child child3{3, 2, "Child of Parent Two"};
    db.insert(child1);
    db.insert(child2);
    db.insert(child3);

    // Verify initial state
    auto children_before = db.select<Child>();
    std::cout << "Children before deletion: " << children_before.size() << std::endl;

    // Delete parent with parent_id = 1
    db.execute("DELETE FROM Parent WHERE parent_id = 1;");

    // Verify cascade deletion
    auto children_after = db.select<Child>();
    std::cout << "Children after deletion: " << children_after.size() << std::endl;

    // Check if children with parent_id = 1 were automatically deleted
    bool cascade_worked = true;

    // Verify that no children with parent_id = 1 remain
    for (const auto& child : children_after) {
        if (child.parent_id == 1) {
            cascade_worked = false;
            break;
        }
    }

    // Verify that child with parent_id = 2 still exists
    bool child_of_parent2_exists = false;
    for (const auto& child : children_after) {
        if (child.parent_id == 2) {
            child_of_parent2_exists = true;
            break;
        }
    }

    // Final verification result
    bool result = cascade_worked && child_of_parent2_exists && (children_after.size() == 1);

    std::cout << "Cascade deletion " << (result ? "worked correctly" : "failed") << std::endl;
    std::cout << "Expected: 1 child remaining (parent_id=2)" << std::endl;
    std::cout << "Actual: " << children_after.size() << " children remaining" << std::endl;

    return result;

  } catch (const std::exception& e) {
    std::cerr << "Error in cascade_delete_demo: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace cascade_delete_demo
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite"
2. **Enables foreign key constraints** (essential for cascade delete to work in SQLite)
3. **Creates the Parent and Child tables** with proper constraints, including the `ON DELETE CASCADE` for the foreign key
4. **Inserts sample data** with parent and child records having the same parent_id
5. **Deletes a parent record** and verifies that the related child records are automatically deleted
6. **Returns a boolean result** indicating whether the cascade deletion worked correctly

The function will return `true` if:
- Children with the deleted parent_id (1) were automatically removed
- Children with other parent_id (2) were preserved
- Exactly one child record remains after the deletion

This demonstrates the cascade deletion behavior as required by the SQL foreign key constraint.

