namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to the SQLite database
  sqlgen::SQLite db("test_db.sqlite");

  // Since SQLite doesn't natively support FULL JOIN, we simulate it using LEFT JOIN and UNION
  // This gives us all suppliers (with their products) and all products (even those without suppliers)
  auto query = sqlgen::query<Supplier, Product>()
      .select<&Supplier::name, &Product::name>()
      .left_join<&Product::supplier_id, &Supplier::supplier_id>()
      .union_all(
          sqlgen::query<Product, Supplier>()
              .select<&Supplier::name, &Product::name>()
              .left_join<&Supplier::supplier_id, &Product::supplier_id>()
              .where(sqlgen::is_null<&Supplier::supplier_id>())
      );

  // Execute the query and map results to SupProd structs
  std::vector<SupProd> results;
  auto rows = db.execute(query);

  for (const auto& row : rows) {
    SupProd item;
    item.supplier_name = std::get<0>(row);  // Supplier name
    if (!std::get<1>(row).empty()) {
      item.product_name = std::get<1>(row);  // Product name (if exists)
    }
    results.push_back(std::move(item));
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

