#include <string>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  JoinAnalysis analysis;

  // Create in-memory database
  sqlgen::SQLiteDB db(":memory:");

  // Create tables
  db.execute(R"(
    CREATE TABLE Department (
      department_id INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location TEXT
    )
  )");

  db.execute(R"(
    CREATE TABLE Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // Insert departments
  auto dept_insert = db.prepare<Department>(R"(
    INSERT INTO Department (department_id, department_name, location)
    VALUES (?, ?, ?)
  )");

  for (const auto& dept : depts) {
    dept_insert.insert(dept);
  }

  // Insert employees
  auto emp_insert = db.prepare<Employee>(R"(
    INSERT INTO Employee (employee_id, department_id, first_name, last_name, salary)
    VALUES (?, ?, ?, ?, ?)
  )");

  for (const auto& emp : emps) {
    emp_insert.insert(emp);
  }

  // INNER JOIN: Employees with assigned departments
  auto inner_join_query = db.prepare<JoinResult>(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    INNER JOIN Employee e ON d.department_id = e.department_id
  )");

  for (const auto& row : inner_join_query.select()) {
    analysis.inner_join_results.push_back(row);
  }

  // LEFT JOIN: All employees (even without departments)
  auto left_join_query = db.prepare<JoinResult>(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
  )");

  for (const auto& row : left_join_query.select()) {
    analysis.left_join_results.push_back(row);
  }

  // RIGHT JOIN: All departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we emulate it
  auto right_join_query = db.prepare<JoinResult>(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    WHERE e.employee_id IS NULL OR e.employee_id IS NOT NULL
  )");

  for (const auto& row : right_join_query.select()) {
    analysis.right_join_results.push_back(row);
  }

  // FULL JOIN: All employees and departments
  // SQLite doesn't support FULL JOIN directly, so we emulate it with UNION
  auto full_join_query = db.prepare<JoinResult>(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
    UNION ALL
    SELECT d.department_name, NULL, NULL, NULL
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    WHERE e.employee_id IS NULL
  )");

  for (const auto& row : full_join_query.select()) {
    analysis.full_join_results.push_back(row);
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. Creates an in-memory SQLite database using `sqlgen::SQLiteDB`
2. Defines the Department and Employee table schemas with appropriate constraints
3. Inserts the provided department and employee data using prepared statements
4. Performs all four types of joins:
   - **INNER JOIN**: Gets only employees with assigned departments
   - **LEFT JOIN**: Includes all employees, even those without departments
   - **RIGHT JOIN**: Includes all departments, even those without employees (emulated since SQLite doesn't natively support RIGHT JOIN)
   - **FULL JOIN**: Includes all employees and departments (emulated using UNION since SQLite doesn't natively support FULL JOIN)
5. Stores the results in the `JoinAnalysis` structure with appropriate optional fields to handle NULL values from outer joins
6. Returns the comprehensive analysis containing all join results

The code handles the optional nature of fields in outer joins by using `std::optional` types in the `JoinResult` structure.

