    .select(
      sqlgen::column<&Product::product_id>(),
      sqlgen::column<&Product::product_name>(),
      sqlgen::column<&Product::category>(),
      sqlgen::sum(sqlgen::column<&Product::price>() * sqlgen::column<&Sales::quantity>()).as("total_sales")
    )
    .from<Product>()
    .inner_join<Sales>().on(sqlgen::column<&Product::product_id>() == sqlgen::column<&Sales::product_id>())
    .group_by(
      sqlgen::column<&Product::product_id>(),
      sqlgen::column<&Product::product_name>(), 
      sqlgen::column<&Product::category>()
    )
    .order_by(sqlgen::column<&TopProduct::total_sales>().desc())
    .limit(limit_count);

  // Execute the query and return results
  return db.execute(query);
}

