```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // SQL query to extract weekday and aggregate total quantities
  auto query = db->prepare(R"(
    SELECT 
      strftime('%w', sale_time) as weekday, 
      SUM(quantity) as total_quantity 
    FROM Sales 
    GROUP BY strftime('%w', sale_time)
    ORDER BY weekday
  )");

  std::vector<WeekdayStats> results;

  // Execute the query and process results
  query->execute([&results](int weekday, int total_quantity) {
    results.push_back(WeekdayStats{weekday, total_quantity});
  });

  return results;
}

}  // namespace weekday_sales_analysis
```

**Key features of this implementation:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish a connection to the SQLite database.

2. **SQL Query**: 
   - Uses `strftime('%w', sale_time)` to extract the weekday (0-6, where 0 is Sunday)
   - Groups by weekday and sums the quantities using `SUM(quantity)`
   - Orders results by weekday for consistent output

3. **Result Processing**: Uses `query->execute()` with a lambda function to populate the `WeekdayStats` vector.

4. **Return Value**: Returns a vector containing weekday numbers and their corresponding total sales quantities.

The function will return results where:
- `weekday` values range from 0 (Sunday) to 6 (Saturday)
- `total_quantity` represents the sum of all sales for that weekday

