};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  // Connect to SQLite database
  sqlgen::SQLite db("test_db.sqlite");

  // Build the SQL query using sqlgen's query builder
  auto query = sqlgen::query<TimeMetrics>()
    .select(
      sqlgen::column<Project>(&Project::project_id),
      sqlgen::column<Project>(&Project::name),
      sqlgen::expr("strftime('%d', {})", sqlgen::column<TimeLog>(&TimeLog::start_time)).as("day"),
      sqlgen::expr("strftime('%m', {})", sqlgen::column<TimeLog>(&TimeLog::start_time)).as("month"),
      sqlgen::expr("strftime('%Y', {})", sqlgen::column<TimeLog>(&TimeLog::start_time)).as("year"),
      sqlgen::expr("strftime('%H', {})", sqlgen::column<TimeLog>(&TimeLog::start_time)).as("hour"),
      sqlgen::expr("strftime('%M', {})", sqlgen::column<TimeLog>(&TimeLog::start_time)).as("minute"),
      sqlgen::expr("strftime('%S', {})", sqlgen::column<TimeLog>(&TimeLog::start_time)).as("second"),
      sqlgen::expr("julianday({}) - julianday({})", 
        sqlgen::column<TimeLog>(&TimeLog::end_time), 
        sqlgen::column<TimeLog>(&TimeLog::start_time)).as("duration_days")
    )
    .from<Project>()
    .inner_join<TimeLog>(sqlgen::on(
      sqlgen::column<Project>(&Project::project_id) == 
      sqlgen::column<TimeLog>(&TimeLog::project_id)
    ));

  // Execute the query and return results
  return db.execute(query);
}

}  // namespace project_time_tracking
