  sqlgen::database<sqlgen::sqlite> db("test_db.sqlite");

  // Execute the query with GROUP BY and aggregations
  return sqlgen::select<Stats>(db,
      "SELECT u.user_id, u.name, "
      "COUNT(p.post_id) as post_count, "
      "AVG(LENGTH(p.content)) as avg_length "
      "FROM User u "
      "LEFT JOIN Post p ON u.user_id = p.user_id "
